ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	"bank_account_detailes": {
		"account_status": {
			"status": "FAILED",
			"statusCode": "404",
			"account_status":vars.status,
			"message": "An account does not exists with the provided customer details. Please try with new details. If you are a new customer, please validate your information."	
		}
	}
}

%dw 2.0
output application/json
---
{
  bankDetails: {
    account_data: {
	  "status": "Success",
	  "statusCode": 200,
      "message": "The account details email has been sent successfully to the user.",
      "data": vars.inputpayload map (item) -> item - "TRANSACTIONS"  }
  }
}

